mapper.select:
SELECT LEVEL as groupLevel, A.* FROM ( SELECT 0 as member_group_idx, 'CMS' AS site_id, 'CMS' AS member_group_name, -1 AS parent_member_group_idx, '' AS remark, 0 AS print_seq, 'Y' AS default_group_yn FROM DUAL UNION ALL SELECT member_group_idx, site_id, member_group_name, parent_member_group_idx, remark, print_seq, default_group_yn FROM WB_MEMBER_GROUP a
WHERE site_id = #{site_id}
) A CONNECT BY PRIOR member_group_idx = parent_member_group_idx START WITH parent_member_group_idx = -1 ORDER SIBLINGS BY site_id, print_seq

SELECT A.member_group_idx FROM WB_MEMBER_GROUP_SUBORD A, WB_MEMBER_GROUP_AUTH B WHERE A.member_group_idx = B.member_group_idx AND A.member_id = #{member_id}
AND B.homepage_id = #{homepage_id}
GROUP BY A.member_group_idx

SELECT LISTAGG(A.member_group_idx, ',') WITHIN GROUP (ORDER BY A.member_group_idx) as member_group_list FROM WB_MEMBER_GROUP_SUBORD A, WB_MEMBER_GROUP B WHERE A.member_group_idx = B.member_group_idx AND A.member_id = #{member_id}
AND B.site_id = #{homepage_id}
ORDER BY B.member_group_idx
